// Global variable to store menu ID
int mainMenu;

// Menu callback function
void menuCallback(int value) {
 switch(value) {
 case 1: printf("Draw Point selected\n"); break;
 case 2: printf("Draw Line selected\n"); break;
 case 3: printf("Clear Screen selected\n"); break;
 case 4: exit(0); break;
 }
 glutPostRedisplay();
}

int main(int argc, char **argv) {
 glutInit(&argc, argv);
 glutInitDisplayMode(GLUT_SINGLE | GLUT_RGB);
 glutCreateWindow("GLUT Menu Demo");

 // Create menu and register callback
 mainMenu = glutCreateMenu(menuCallback);

 // Add menu entries with values
 glutAddMenuEntry("Draw Point", 1);
 glutAddMenuEntry("Draw Line", 2);
 glutAddMenuEntry("Clear Screen", 3);
 glutAddMenuEntry("Exit", 4);

 // Attach menu to right mouse button
 glutAttachMenu(GLUT_RIGHT_BUTTON);

 glutDisplayFunc(display);
 glutMainLoop();
 return 0;
}

