int shapesMenu, colorsMenu, mainMenu;

void menuCallback(int value) {
 if (value == 1) { /* Draw point */ }
 else if (value == 2) { /* Draw line */ }
 else if (value == 3) { /* Draw triangle */ }
 else if (value == 10) { /* Set red */ }
 else if (value == 11) { /* Set green */ }
 else if (value == 12) { /* Set blue */ }
 else if (value == 99) { /* Clear screen */ }
 else if (value == 100) { /* Exit */ }
}

void createMenus() {
 // Create shapes submenu first
 shapesMenu = glutCreateMenu(menuCallback);
 glutAddMenuEntry("Point", 1);
 glutAddMenuEntry("Line", 2);
 glutAddMenuEntry("Triangle", 3);

 // Create colors submenu
 colorsMenu = glutCreateMenu(menuCallback);
 glutAddMenuEntry("Red", 10);
 glutAddMenuEntry("Green", 11);
 glutAddMenuEntry("Blue", 12);

 // Create main menu and add submenus
 mainMenu = glutCreateMenu(menuCallback);
 glutAddSubMenu("Shapes", shapesMenu);
 glutAddSubMenu("Colors", colorsMenu);
 glutAddMenuEntry("Clear Screen", 99);
 glutAddMenuEntry("Exit", 100);

 // Attach to right button
 glutAttachMenu(GLUT_RIGHT_BUTTON);
}

int main(int argc, char **argv) {
 glutInit(&argc, argv);
 glutInitDisplayMode(GLUT_DOUBLE | GLUT_RGB);
 glutCreateWindow("Hierarchical Menu Demo");

 createMenus();

 glutDisplayFunc(display);
 glutMainLoop();
 return 0;
}

int currentMenu = 0;

void primaryMenuCallback(int value) {
 if (value == 1) {
 // Switch to alternate menu
 glutDetachMenu(GLUT_RIGHT_BUTTON);
 glutDestroyMenu(currentMenu);
 currentMenu = createAlternateMenu();
 glutAttachMenu(GLUT_RIGHT_BUTTON);
 } else if (value == 2) {
 // Exit application
 glutDestroyMenu(currentMenu);
 exit(0);
 }
}

int createPrimaryMenu() {
 int menu = glutCreateMenu(primaryMenuCallback);
 glutAddMenuEntry("Switch to Mode 2", 1);
 glutAddMenuEntry("Exit", 2);
 return menu;
}

int createAlternateMenu() {
 int menu = glutCreateMenu(primaryMenuCallback);
 glutAddMenuEntry("Option A", 10);
 glutAddMenuEntry("Option B", 11);
 glutAddMenuEntry("Switch to Mode 1", 12);
 glutAddMenuEntry("Exit", 2);
 return menu;
}

int main(int argc, char **argv) {
 glutInit(&argc, argv);
 glutCreateWindow("Dynamic Menu Demo");

 currentMenu = createPrimaryMenu();
 glutAttachMenu(GLUT_RIGHT_BUTTON);

 glutMainLoop();
 return 0;
}
